import { Injectable, inject } from '@angular/core';
import { Router } from '@angular/router';
import { TRPC_CLIENT } from '../app.config';
import { AuthService } from './auth.service';
import {
  Account,
  AuthUser,
  Contact,
  CrmTask,
  Lead,
  LeadStatus,
  Opportunity,
  Role,
  Stage,
} from './models';

/** Raw row shapes returned by the backend tRPC procedures (JSON-serialized). */
interface RawAccount {
  id: string;
  name: string;
  industry: string | null;
}
interface RawContact {
  id: string;
  name: string;
  email: string | null;
  phone: string | null;
  accountId: string;
  account?: { name?: string } | null;
}
interface RawOpportunity {
  id: string;
  name: string;
  amount: number;
  stage: Stage;
  accountId: string;
  account?: { name?: string } | null;
}
interface RawLead {
  id: string;
  name: string;
  email: string | null;
  phone: string | null;
  status: LeadStatus;
}
interface RawTask {
  id: string;
  title: string;
  dueDate: string;
  done: boolean;
}
interface RawUser {
  id: string;
  name: string | null;
  email: string;
  role: Role;
}
interface RawAccountDetail extends RawAccount {
  contacts: RawContact[];
  opportunities: RawOpportunity[];
}

export interface DashboardSummary {
  accounts: number;
  contacts: number;
  openOpportunities: number;
  upcomingTasks: number;
}

export interface AccountDetail {
  account: Account;
  contacts: Contact[];
  opportunities: Opportunity[];
}

/**
 * Single gateway between the Angular UI and the NestJS tRPC backend.
 *
 * Responsibilities:
 *  - expose one typed async method per backend procedure
 *  - normalize backend rows into the frontend view models (core/models.ts)
 *  - centralize the 401 → clear-session → redirect-to-login behavior
 */
@Injectable({ providedIn: 'root' })
export class ApiService {
  private readonly trpc = inject(TRPC_CLIENT) as any;
  private readonly router = inject(Router);
  private readonly auth = inject(AuthService);

  // ---- Accounts -----------------------------------------------------------

  async listAccounts(): Promise<Account[]> {
    const rows: RawAccount[] = await this.call(() => this.trpc.account.list.query());
    return rows.map(mapAccount);
  }

  async accountDetail(id: string): Promise<AccountDetail> {
    const row: RawAccountDetail = await this.call(() =>
      this.trpc.account.byId.query({ id }),
    );
    return {
      account: mapAccount(row),
      contacts: (row.contacts ?? []).map((c) => mapContact({ ...c, account: { name: row.name } })),
      opportunities: (row.opportunities ?? []).map((o) =>
        mapOpportunity({ ...o, account: { name: row.name } }),
      ),
    };
  }

  async createAccount(input: { name: string; industry?: string }): Promise<Account> {
    const row: RawAccount = await this.call(() => this.trpc.account.create.mutate(input));
    return mapAccount(row);
  }

  async updateAccount(input: {
    id: string;
    name?: string;
    industry?: string;
  }): Promise<Account> {
    const row: RawAccount = await this.call(() => this.trpc.account.update.mutate(input));
    return mapAccount(row);
  }

  // ---- Contacts -----------------------------------------------------------

  async listContacts(): Promise<Contact[]> {
    const rows: RawContact[] = await this.call(() => this.trpc.contact.list.query());
    return rows.map(mapContact);
  }

  async createContact(input: {
    name: string;
    email?: string;
    phone?: string;
    accountId: string;
  }): Promise<Contact> {
    const row: RawContact = await this.call(() => this.trpc.contact.create.mutate(input));
    return mapContact(row);
  }

  // ---- Opportunities ------------------------------------------------------

  async listOpportunities(): Promise<Opportunity[]> {
    const rows: RawOpportunity[] = await this.call(() =>
      this.trpc.opportunity.list.query(),
    );
    return rows.map(mapOpportunity);
  }

  async createOpportunity(input: {
    name: string;
    amount: number;
    stage: Stage;
    accountId: string;
  }): Promise<Opportunity> {
    const row: RawOpportunity = await this.call(() =>
      this.trpc.opportunity.create.mutate(input),
    );
    return mapOpportunity(row);
  }

  async updateOpportunityStage(id: string, stage: Stage): Promise<Opportunity> {
    const row: RawOpportunity = await this.call(() =>
      this.trpc.opportunity.updateStage.mutate({ id, stage }),
    );
    return mapOpportunity(row);
  }

  // ---- Leads --------------------------------------------------------------

  async listLeads(): Promise<Lead[]> {
    const rows: RawLead[] = await this.call(() => this.trpc.lead.list.query());
    return rows.map(mapLead);
  }

  async createLead(input: {
    name: string;
    email?: string;
    status?: LeadStatus;
  }): Promise<Lead> {
    const row: RawLead = await this.call(() => this.trpc.lead.create.mutate(input));
    return mapLead(row);
  }

  // ---- Tasks --------------------------------------------------------------

  async listTasks(): Promise<CrmTask[]> {
    const rows: RawTask[] = await this.call(() => this.trpc.task.list.query());
    return rows.map(mapTask);
  }

  async upcomingTasks(): Promise<CrmTask[]> {
    const rows: RawTask[] = await this.call(() => this.trpc.task.upcoming.query());
    return rows.map(mapTask);
  }

  async createTask(input: { title: string; dueDate: string }): Promise<CrmTask> {
    const row: RawTask = await this.call(() => this.trpc.task.create.mutate(input));
    return mapTask(row);
  }

  // ---- Dashboard ----------------------------------------------------------

  async dashboardSummary(): Promise<DashboardSummary> {
    return this.call(() => this.trpc.dashboard.summary.query());
  }

  // ---- Internals ----------------------------------------------------------

  /**
   * Runs a tRPC call and, on an authentication failure (401 / UNAUTHORIZED),
   * clears the session and redirects to /login — the app-wide auth interceptor.
   */
  private async call<T>(fn: () => Promise<T>): Promise<T> {
    try {
      return await fn();
    } catch (err) {
      if (isUnauthorized(err)) {
        this.auth.clearSession();
        void this.router.navigate(['/login']);
      }
      throw err;
    }
  }
}

// ---- Mappers --------------------------------------------------------------

function mapAccount(row: RawAccount): Account {
  return {
    id: row.id,
    name: row.name,
    industry: row.industry ?? '',
  };
}

function mapContact(row: RawContact): Contact {
  return {
    id: row.id,
    name: row.name,
    email: row.email ?? '',
    phone: row.phone ?? '',
    accountId: row.accountId,
    accountName: row.account?.name ?? 'Unassigned',
  };
}

function mapOpportunity(row: RawOpportunity): Opportunity {
  return {
    id: row.id,
    name: row.name,
    amount: row.amount,
    stage: row.stage,
    accountId: row.accountId,
    accountName: row.account?.name ?? 'Unassigned',
  };
}

function mapLead(row: RawLead): Lead {
  return {
    id: row.id,
    name: row.name,
    company: '',
    email: row.email ?? '',
    status: row.status,
  };
}

function mapTask(row: RawTask): CrmTask {
  return {
    id: row.id,
    title: row.title,
    dueDate: String(row.dueDate).slice(0, 10),
    status: row.done ? 'Completed' : 'Open',
    relatedTo: '',
  };
}

/** True when a tRPC client error represents an authentication failure. */
function isUnauthorized(err: unknown): boolean {
  const e = err as {
    data?: { code?: string; httpStatus?: number };
    shape?: { data?: { code?: string; httpStatus?: number } };
  };
  const code = e?.data?.code ?? e?.shape?.data?.code;
  const status = e?.data?.httpStatus ?? e?.shape?.data?.httpStatus;
  return code === 'UNAUTHORIZED' || status === 401;
}

/** Extracts a human-friendly message from a tRPC/HTTP error. */
export function errorMessage(err: unknown, fallback = 'Something went wrong.'): string {
  const e = err as { message?: string };
  return e?.message || fallback;
}
